grel:if(
  isBlank(value),
  null,
  with(
    value.match(
      /^.*?\b((?:1[5-9]\d{2}|20\d{2}))\s*[-–]\s*((?:1[5-9]\d{2}|20\d{2})|\d{2})\b.*$/
    ),
    years,
    if(
      years == null,
      null,
      if(
        years[1].length() == 2,
        years[0].substring(0,2) + years[1],
        years[1]
      )
    )
  )
)

