expression:
grel:with(
  cells["Place_before_colon"].value,
  before,
  with(
    cells["Place_after_colon"].value,
    after,
    if(
      isBlank(before),
      after,
      if(
        and(
          not(isBlank(after)),
          or(
            before.match(/.*\b(pp\.|printed|printer|press|publisher|published|privately|office|author|society|company|co\.?|sons?|bros\.?|etc\.?)\b.*/i) != null,
            before.match(/^[A-Z]\.\s+.*$/) != null
          )
        ),
        after,
        before
      )
    )
  )
)

