expression:
grel:with(
  cells["Publication_place_final"].value,
  place,
  with(
    cells["Place_before_colon"].value,
    before,
    with(
      cells["Place_after_colon"].value,
      after,
      with(
        before.replace("[printed]", "").replace("[printed", "").replace(" printed", "").trim(),
        before_clean,
        if(
          or(isBlank(place), isBlank(before), isBlank(after)),
          null,
          if(
            before_clean.toLowercase() == place.trim().toLowercase(),
            after.trim(),
            if(
              after.trim().toLowercase() == place.trim().toLowercase(),
              before_clean,
              null
            )
          )
        )
      )
    )
  )
)

